/**
 * InputField Component
 *
 * 再利用可能な入力フィールドコンポーネント。
 * ラベル、エラーメッセージ、バリデーション表示をサポートします。
 *
 * 使用例:
 * ```tsx
 * <InputField
 *   type="email"
 *   label="Email Address"
 *   value={email}
 *   onChange={(e) => setEmail(e.target.value)}
 *   error="Invalid email address"
 *   required
 * />
 * ```
 */

import React, { InputHTMLAttributes } from 'react';

export interface InputFieldProps extends Omit<InputHTMLAttributes<HTMLInputElement>, 'onChange'> {
  /** 入力フィールドのラベル */
  label?: string;
  /** エラーメッセージ（表示する場合） */
  error?: string;
  /** 値変更時のコールバック */
  onChange?: (e: React.ChangeEvent<HTMLInputElement>) => void;
  /** 追加のコンテナCSSクラス */
  containerClassName?: string;
}

/**
 * InputFieldコンポーネント
 * ラベル、エラー表示付きの入力フィールドを提供します
 */
const InputField: React.FC<InputFieldProps> = ({
  label,
  error,
  onChange,
  containerClassName = '',
  className = '',
  type = 'text',
  id,
  required,
  ...rest
}) => {
  // IDが指定されていない場合、ラベルから生成
  const fieldId = id || (label ? `input-${label.toLowerCase().replace(/\s+/g, '-')}` : undefined);

  // エラー時のスタイル
  const inputClasses = `
    w-full px-4 py-2 border rounded-lg focus:outline-none focus:ring-2 transition-colors
    ${
      error
        ? 'border-red-500 focus:ring-red-500 focus:border-red-500'
        : 'border-gray-300 focus:ring-primary-500 focus:border-primary-500'
    }
    ${className}
  `.trim();

  return (
    <div className={`mb-4 ${containerClassName}`}>
      {/* Label */}
      {label && (
        <label htmlFor={fieldId} className="block text-sm font-medium text-gray-700 mb-1">
          {label}
          {required && <span className="text-red-500 ml-1">*</span>}
        </label>
      )}

      {/* Input Field */}
      <input
        id={fieldId}
        type={type}
        onChange={onChange}
        required={required}
        className={inputClasses}
        aria-invalid={error ? 'true' : 'false'}
        aria-describedby={error ? `${fieldId}-error` : undefined}
        {...rest}
      />

      {/* Error Message */}
      {error && (
        <p id={`${fieldId}-error`} className="mt-1 text-sm text-red-600" role="alert">
          {error}
        </p>
      )}
    </div>
  );
};

export default InputField;
